import React, { useState, useRef } from 'react';
import { SpotterEmbed, useEmbedRef } from '@thoughtspot/visual-embed-sdk/react';
import { HostEvent, EmbedEvent } from '@thoughtspot/visual-embed-sdk';
import './config/thoughtspot';
import './App.css';
import WordCloud from './WordCloud';

const INDUSTRIES = [
  {
    id: 'finance',
    label: 'Finance',
    icon: '💹',
    worksheetId: 'af07f762-1854-4a80-8bdb-9250ee49ad1e',
    enabled: true,
    questions: [
      { text: 'Who are the top advisors by AUM?', size: 'xl' },
      { text: 'Show me asset allocation by class', size: 'lg' },
      { text: 'Which clients have the highest liabilities?', size: 'md' },
      { text: 'Average risk score by income category', size: 'lg' },
      { text: 'How many clients per advisor?', size: 'md' },
      { text: 'Break down assets by age group', size: 'sm' },
      { text: 'What is the total market value by sector?', size: 'xl' },
    ],
  },
  { id: 'industry2', label: 'Industry 2', icon: '🏭', worksheetId: null, enabled: false, questions: [] },
  { id: 'industry3', label: 'Industry 3', icon: '🌐', worksheetId: null, enabled: false, questions: [] },
  {
    id: 'fun',
    label: 'Just For Fun',
    icon: '🏅',
    worksheetId: 'acdd8a7c-975a-4664-81a4-e715df113864',
    enabled: true,
    questions: [
      { text: 'Which country has the most medals?', size: 'xl' },
      { text: 'Show me top sports by athlete count', size: 'lg' },
      { text: 'Who are the most decorated athletes?', size: 'xl' },
      { text: 'Compare Summer vs Winter Games', size: 'md' },
      { text: 'Average age by sport', size: 'lg' },
      { text: 'Medal trends over time', size: 'md' },
      { text: 'Which events have the tallest athletes?', size: 'sm' },
    ],
  },
];

export default function App() {
  const [selected, setSelected] = useState(INDUSTRIES[3]); // default: Just For Fun
  const [hintVisible, setHintVisible] = useState(true);
  const [expanded, setExpanded] = useState(false);
  const [activeQuestion, setActiveQuestion] = useState(null);
  const embedRef = useEmbedRef();
  const pendingQueryRef = useRef(null); // stores question to fire after Spotter loads

  const fireQuery = (query) => {
    if (embedRef.current) {
      embedRef.current.trigger(HostEvent.SpotterSearch, {
        query,
        executeSearch: true,
      });
    }
  };

  const handleQuestionSelect = (query) => {
    setHintVisible(false);
    setExpanded(true);
    setActiveQuestion(query);
    // Small delay to let React finish re-rendering before triggering
    setTimeout(() => {
      if (embedRef.current) {
        embedRef.current.trigger(HostEvent.SpotterSearch, {
          query,
          executeSearch: true,
        });
      }
    }, 800);
  };
  const handleDatasetSwitch = (ind) => {
    if (!ind.enabled) return;
    setSelected(ind);
    setHintVisible(true);
    setExpanded(false);
    setActiveQuestion(null);
    pendingQueryRef.current = null;
  };

  // Called when Spotter finishes loading — fires any pending query
  const handleSpotterLoad = () => {
    if (pendingQueryRef.current) {
      const query = pendingQueryRef.current;
      pendingQueryRef.current = null;
      setTimeout(() => fireQuery(query), 500);
    }
  };

  return (
    <div className="app">
      <div className="bg" />
      <div className="grid-lines" />

      {/* Header */}
      <header className="header">
        <div className="header-left">
          <img src="/thoughtspot_logo.jpeg" alt="ThoughtSpot" className="ts-logo-img" />
          <span className="ts-wordmark">Thought<span>Spot</span></span>
        </div>
        <div className="header-right">
          <div className="header-event-info">
            <span className="header-event-name">Data Innovation Summit 2026</span>
            <span className="header-event-sub">6–8 May · Kistamässan, Stockholm · DIS2026X1</span>
          </div>
        </div>
      </header>

      {/* Hero */}
      <section className="hero">
        <h1 className="hero-title">
          Meet <span className="highlight">Spotter</span> -<br />your AI Analyst
        </h1>
        <p className="hero-subtitle">
          Ask questions, explore insights, and discover what's shaping the future of data. Powered by ThoughtSpot.
        </p>

        {/* Industry selector */}
        <div className="industry-selector">
          <span className="industry-selector-label">Step 1: Choose your industry</span>
          <div className="industry-buttons">
            {INDUSTRIES.map((ind) => (
              <button
                key={ind.id}
                className={`industry-btn ${selected.id === ind.id ? 'industry-btn--active' : ''} ${!ind.enabled ? 'industry-btn--disabled' : ''}`}
                onClick={() => handleDatasetSwitch(ind)}
                disabled={!ind.enabled}
                title={!ind.enabled ? 'Coming soon' : ind.label}
              >
                <span className="industry-btn-icon">{ind.icon}</span>
                <span className="industry-btn-label">{ind.label}</span>
                {!ind.enabled && <span className="industry-btn-soon">Soon</span>}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Word cloud */}
      <WordCloud onSelect={handleQuestionSelect} questions={selected.questions} activeQuestion={activeQuestion} />

      {/* Spotter embed — key forces remount only on dataset/worksheet switch */}
      <div className="spotter-wrapper">
        <div className="spotter-glow" />
        <div className="spotter-card">
          {hintVisible && !expanded && (
            <div className="spotter-card-hint">
              Type your question below<br />or pick an example from the list ⬆️
            </div>
          )}
          <div
            className={`spotter-embed-area ${expanded ? 'spotter-embed-expanded' : 'spotter-embed-compact'}`}
            onClick={() => { setHintVisible(false); setExpanded(true); }}
          >
            <SpotterEmbed
              key={selected.worksheetId}
              ref={embedRef}
              worksheetId={selected.worksheetId}
              frameParams={{ height: '700px', width: '100%' }}
              hideSampleQuestions={false}
              disableSourceSelection={true}
              onLoad={handleSpotterLoad}
              onError={(e) => console.error('Spotter error:', e)}
            />
          </div>
        </div>
      </div>

      {/* Event stats strip */}
      <div className="event-strip">
        <div className="strip-item">
          <span className="strip-value">3,500+</span>
          <span className="strip-label">Delegates</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">300+</span>
          <span className="strip-label">Speakers</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">15</span>
          <span className="strip-label">Stages</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">3 Days</span>
          <span className="strip-label">6–8 May 2026</span>
        </div>
        <div className="strip-sep" />
        <div className="strip-item">
          <span className="strip-value">100+</span>
